UPDATE modules SET
  slug              = 'les_professions',
  title_al          = 'Les professions',
  title_ll          = 'Jobs & Professions',
  description_al    = 'Découvrez les noms des métiers et apprenez à décrire votre travail en anglais.',
  icon_name         = 'briefcase',
  color_hex         = '#9B59B6',
  difficulty_level  = 2,
  is_published      = true,
  xp_reward         = 100,
  estimated_minutes = 15
WHERE slug = 'shell_module_20';

VALUES (gen_random_uuid(), (SELECT id FROM modules WHERE slug = 'les_professions'), 'les_professions_lesson_1', 'Les métiers', 1, 'standard', 50, true);


